local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn(TD.holder("%s_wing"), function(inst)     TD.server(function()         if inst and inst.AnimState then             inst.AnimState:OverrideSymbol("swap_body", TD.holder("swap_%s_wing"), "swap_body")         end     end) end) TD.createFn(TD.holder("%s_hat"), function(inst)     TD.server(function()         if inst and inst.AnimState then             inst.AnimState:Show("HAT")             inst.AnimState:Show("HAIR_HAT")             inst.AnimState:Hide("HAIR_NOHAT")             inst.AnimState:Hide("HAIR")             if inst:HasTag("player") then                 inst.AnimState:Hide("HEAD")                 inst.AnimState:Show("HEAD_HAT")             end             inst.AnimState:OverrideSymbol("swap_hat", TD.holder("%s_hat"), "swap_hat")         end     end) end) TD.createFn(TD.holder("%s_withdrawWing"), function(inst)     TD.server(function()         if inst and inst.AnimState then             inst.AnimState:ClearOverrideSymbol("swap_body")         end     end) end) local expRaise = TD.num("1.5") local expRaise2 = TD.num("1.01") local expBase = TD.num("20") TD.createFn("baseExp", function(lv, exp)     if not TD.isPos(lv) or not TD.isNative(exp) then         return 1     end     local lvMiddle = 15     if lv <= lvMiddle then         return math.ceil(math.pow(expRaise, (lv - 1)) * expBase)     end     local expBase2 = math.ceil(math.pow(expRaise, (lvMiddle - 1)) * expBase)     return math.ceil(math.pow(expRaise2, (lv - (lvMiddle - 1))) * expBase2) end) TD.createFn(TD.holder("%s_obtainExp"), function(player, expObtain)     if not player or not TD.isPos(expObtain) then         return     end     local lv = (TD.csv(player):get(TD.holder("%s_lv")) or 1)     local exp = (TD.csv(player):get(TD.holder("%s_exp")) or 0)          local bufferExp = player.bufferExp     if not bufferExp then         bufferExp = 0     end     bufferExp = bufferExp + expObtain     player.bufferExp = bufferExp               local TD_EXP_BUFFER_TASK = "TD_EXP_BUFFER_TASK"     local TD_EXP_BUFFER_TASK_EXP = "TD_EXP_BUFFER_TASK_EXP"     TD.removeTask(player, TD_EXP_BUFFER_TASK)     player[TD_EXP_BUFFER_TASK] = TD.latter(player, 0.1, function()                           local base = TD.baseExp(lv, exp)         local finalExp = exp + bufferExp         local leveluped = false         while finalExp >= base do                          finalExp = finalExp - base             lv = lv + 1             base = TD.baseExp(lv, exp)             leveluped = true         end                  if leveluped then             TD.color(TD.below(player, "statue_transition"), 0, .5, 1).Transform:SetScale(2, 2, 2)             TD.color(TD.below(player, "explode_small"), .5, 1, 1).Transform:SetScale(2, 2, 2)         end                  TD.csv(player):value(TD.holder("%s_lv"), lv, true)         TD.removeTask(player, TD_EXP_BUFFER_TASK_EXP)                  player[TD_EXP_BUFFER_TASK_EXP] = TD.latter(player, 0.05, function()                          player.bufferExp = nil                          TD.csv(player):value(TD.holder("%s_exp"), finalExp, true)             if bufferExp >= 5 then                 TD.talk(player, string.format(TD.showStr("获得经验%s", "Gain EXP %s"), bufferExp))             end         end)              end) end) 